// ════════════════════════════════════════════════════════════════
//  HELPERS
// ════════════════════════════════════════════════════════════════
function showErr(id, msg) {
  const el=document.getElementById(id);
  el.classList.add('show');
  if(msg) { const span=el.querySelector('span:last-child'); if(span) span.textContent=msg; }
  setTimeout(()=>el.classList.remove('show'),5000);
}
function hideErr(id) { document.getElementById(id).classList.remove('show'); }

function setBtnLoading(btnId, spinnerId, textId, loading) {
  const btn=document.getElementById(btnId);
  const sp=document.getElementById(spinnerId);
  const tx=document.getElementById(textId);
  btn.disabled=loading;
  if(sp) sp.style.display=loading?'':'none';
  if(tx) tx.style.display=loading?'none':'';
}

let _toastTimer;
function toast(msg, type='') {
  clearTimeout(_toastTimer);
  const el=document.getElementById('toast');
  el.textContent=msg;
  el.className='toast show '+(type||'');
  _toastTimer=setTimeout(()=>{el.className='toast '+(type||'');},3500);
}
